export type TemplateVisibility = "public" | "private" | "unlisted";

export type BusinessTemplate = {
  id: string;
  name: string;
  description: string;
  icon: string;
  category: "service" | "ecommerce" | "content" | "agency" | "custom";
  tags: string[];
  defaults: {
    summary?: string;
    brandVoice?: string;
    mainGoals?: string;
    coreOffers?: string;
    offerAndAudienceNotes?: string;
    safetyMode?: string;
    primaryModel?: string;
    // Fallback model used when the primaryModel provider returns an outage,
    // rate-limit, or other recoverable error. Defaults to the platform's
    // default fallback when unset. Pin both fields per template so output
    // quality stays predictable as platform defaults shift.
    fallbackModel?: string;
    // Per-template spend ceilings (USD). When any of these are set, the
    // runtime tracks usage in BusinessActivity / SpendLedger and halts the
    // associated agent loop when exceeded. The agent system prompt
    // (composed via composeAgentSystemPrompt) surfaces these to the agent
    // so it self-throttles before hitting the hard halt.
    spendCeilings?: {
      weeklyVideoGen?: number;
      weeklyColdEmail?: number;
      weeklySmsBlast?: number;
      weeklyImageGen?: number;
      weeklyVoiceGen?: number;
      monthlyTotalCap?: number;
    };
  };
  systemPromptTemplate: string;
  guardrailsTemplate: string;
  starterAgents: StarterAgentTemplate[];
  starterWorkflows: StarterWorkflowTemplate[];
  starterKnowledge: StarterKnowledgeTemplate[];
  starterWorkspaceDocs: StarterDocTemplate[];
  starterSkills?: StarterSkillTemplate[];
  // MCP ids (from lib/integrations/mcp-definitions.ts) the template relies on
  // for end-to-end functionality. Surfaced in the Day 1 Setup Checklist so
  // operators know what to install before expecting agents to execute.
  requiredIntegrations?: string[];
  // Optional MCPs that unlock additional capability but aren't blocking.
  suggestedIntegrations?: string[];
  // Optional toggleable bundles the operator can opt into at create time.
  // Each addon merges its extraAgents/Workflows/Knowledge into the
  // materialized business when its id is in `selectedAddonIds` at create
  // time. Used by tiktok_shop to keep the off-platform digital ladder
  // (Stripe/Resend, lead magnets, email funnel) optional rather than
  // required for operators who only sell on TikTok Shop.
  addons?: TemplateAddon[];
  // Defaults to "public" when unset. "private" and "unlisted" templates are
  // only visible to — and instantiable by — sessions whose email is in
  // `ownerEmails` (case-insensitive). The server enforces this in
  // /api/admin/businesses POST; the client-side selector filter is a UX
  // courtesy, not the security gate.
  visibility?: TemplateVisibility;
  // Required when `visibility` is "private" or "unlisted". Any session whose
  // email matches (case-insensitive) one of these is treated as an owner —
  // grants access to see + instantiate the template. Use a list so hired
  // staff can be granted access without sharing login credentials.
  ownerEmails?: string[];
};

export type TemplateAddon = {
  id: string;
  name: string;
  description: string;
  // When true, the onboarding UI pre-selects this addon. Defaults false.
  enabledByDefault?: boolean;
  // Additional MCPs this addon needs. Surfaced as a hard prerequisite when
  // the operator opts in — the API route blocks creation if they aren't
  // installed. Empty / omitted = addon adds no integration requirements.
  extraRequiredIntegrations?: string[];
  // Additional optional MCPs surfaced alongside the addon.
  extraSuggestedIntegrations?: string[];
  extraAgents?: StarterAgentTemplate[];
  extraWorkflows?: StarterWorkflowTemplate[];
  extraKnowledge?: StarterKnowledgeTemplate[];
  extraWorkspaceDocs?: StarterDocTemplate[];
  // Appended to the template's systemPromptTemplate when this addon is
  // enabled — lets the addon teach the existing agents about the new
  // surface (e.g. dual-channel revenue model) without forking every agent.
  systemPromptAddendum?: string;
  // Appended to the template's guardrailsTemplate when enabled.
  guardrailsAddendum?: string;
};

