export type TemplateSubstitutionContext = {
  businessName: string;
  affiliateLink?: string;
  /** Operator (the human running the business) — surfaces in templates via
   *  {{operatorName}}, {{operatorPhone}}, {{operatorEmail}}. Used to be
   *  hardcoded "Brandon" in the private GPC + TRA templates; now editable
   *  per-business. Defaults to the empty string when unset so the prompt
   *  stays grammatical ("escalate to" vs "escalate to {{operatorName}}"). */
  operatorName?: string;
  operatorPhone?: string;
  operatorEmail?: string;
  /** External escalation contact (e.g. a CPA, attorney, account manager)
   *  that the agent hands off to when it hits a hard limit. Used to be
   *  hardcoded "Dave at (410) 404-2880" in tiptax; now editable per-business. */
  escalationContactName?: string;
  escalationContactPhone?: string;
};

const DEFAULT_TIPTAX_AFFILIATE_LINK = "https://tiptaxrefund.org/9fpc";

/**
 * Substitute template placeholders. Accepts either a string (legacy — only
 * businessName substitution) or a context object with businessName + optional
 * affiliateLink. Used by materializeTemplate when seeding agents, workflows,
 * knowledge, and workspace docs — and also by the create API route when
 * pre-rendering the systemPrompt/guardrails before materialization.
 *
 * {{affiliateLink}} falls back to the TipTax default when not provided; only
 * tiptax_affiliate_engine uses this placeholder today but the helper is
 * template-neutral so future templates can reuse it.
 */
function applyContext(
  template: string,
  contextOrBusinessName: string | TemplateSubstitutionContext
): string {
  const ctx: TemplateSubstitutionContext =
    typeof contextOrBusinessName === "string"
      ? { businessName: contextOrBusinessName }
      : contextOrBusinessName;
  return template
    .replaceAll("{{businessName}}", ctx.businessName)
    .replaceAll(
      "{{affiliateLink}}",
      ctx.affiliateLink ?? DEFAULT_TIPTAX_AFFILIATE_LINK
    )
    .replaceAll("{{operatorName}}", ctx.operatorName ?? "")
    .replaceAll("{{operatorPhone}}", ctx.operatorPhone ?? "")
    .replaceAll("{{operatorEmail}}", ctx.operatorEmail ?? "")
    .replaceAll("{{escalationContactName}}", ctx.escalationContactName ?? "")
    .replaceAll("{{escalationContactPhone}}", ctx.escalationContactPhone ?? "");
}

/**
 * Generate a "Day 1 Setup Checklist" knowledge item that tells the operator
 * exactly what to install, configure, and prepare before agents can execute
 * real work (vs. just drafting). Gets prepended to every template's
 * starterKnowledge array so it's the first thing users read in the KB.
 *
 * This is deliberately operator-facing: concrete MCP install steps, account
 * links, and credentials needed — the single biggest gap flagged in the
 * April 2026 template audit.
 */
function setupChecklistKb(body: {
  templateName: string;
  summary: string;
  requiredMcps: Array<{ label: string; why: string }>;
  suggestedMcps?: Array<{ label: string; why: string }>;
  accountsAndCredentials?: string[];
  firstWeekActions?: string[];
  unavailableButReferenced?: Array<{ label: string; note: string }>;
}): StarterKnowledgeTemplate {
  const lines: string[] = [];
  lines.push(`# Day 1 Setup Checklist — ${body.templateName}`);
  lines.push("");
  lines.push(body.summary);
  lines.push("");
  lines.push("## 1. Install required MCP integrations");
  lines.push(
    "Open /admin/integrations and install each of the following. Without these, the matching agent workflows can only draft — they cannot execute."
  );
  if (body.requiredMcps.length === 0) {
    lines.push(
      "- No third-party MCPs are strictly required for {{businessName}} — the built-in toolkit covers the baseline."
    );
  } else {
    for (const m of body.requiredMcps) {
      lines.push(`- **${m.label}** — ${m.why}`);
    }
  }
  lines.push("");
  if (body.suggestedMcps && body.suggestedMcps.length > 0) {
    lines.push("## 2. Suggested integrations (optional but high leverage)");
    for (const m of body.suggestedMcps) {
      lines.push(`- **${m.label}** — ${m.why}`);
    }
    lines.push("");
  }
  if (body.accountsAndCredentials && body.accountsAndCredentials.length > 0) {
    lines.push("## 3. External accounts & credentials to prepare");
    for (const item of body.accountsAndCredentials) {
      lines.push(`- ${item}`);
    }
    lines.push("");
  }
  if (body.firstWeekActions && body.firstWeekActions.length > 0) {
    lines.push("## 4. First-week actions");
    for (const [idx, action] of body.firstWeekActions.entries()) {
      lines.push(`${idx + 1}. ${action}`);
    }
    lines.push("");
  }
  if (
    body.unavailableButReferenced &&
    body.unavailableButReferenced.length > 0
  ) {
    lines.push("## 5. Tools your agents describe but that require manual setup");
    lines.push(
      "The agent system prompts for {{businessName}} reference the following tools that are **not** wired as MCPs. Agents will describe using them — you need to run them yourself."
    );
    for (const t of body.unavailableButReferenced) {
      lines.push(`- **${t.label}** — ${t.note}`);
    }
    lines.push("");
  }
  lines.push("---");
  lines.push(
    "When you've completed this checklist, mark it done in /admin/knowledge and your agents will stop asking about setup in their briefings."
  );

  return {
    category: "setup",
    title: "Day 1 Setup Checklist",
    contentTemplate: lines.join("\n")
  };
}

/**
 * Blotato Operational Playbook — codifies the canonical Blotato workflow
 * patterns (E2E recipe, polling cadences, failure semantics, per-platform
 * required fields, fan-out, schedule slots, plan caps) as a single
 * StarterKnowledgeTemplate so the agents can find this guidance in RAG
 * lookup at planning time rather than re-deriving it from per-tool
 * descriptions on every run.
 *
 * Called from the heavy-7 templates that wire blotato_mcp as required.
 * Folded in from Blotato's LLM-optimized docs (help.blotato.com/api/llm.md,
 * /api/workflows.md, /api/mcp.md, the Build-Your-First tutorial).
 */
export function blotatoOperationalPlaybookKb(body: {
  templateName: string;
  useCases: string[];
  workedExample: string;
}): StarterKnowledgeTemplate {
  const lines: string[] = [];
  lines.push(`# Blotato Operational Playbook — ${body.templateName}`);
  lines.push("");
  lines.push(
    "Blotato is {{businessName}}'s unified cross-platform publishing + AI visual-generation + content-extraction layer across TikTok, Instagram, YouTube, X, LinkedIn, Threads, Facebook, Pinterest, and Bluesky. This playbook codifies the canonical workflow patterns Blotato publishes for agent consumption. Tools live in the `blotato_*` family; the operator wires the integration once and the agents follow the recipes below."
  );
  lines.push("");
  lines.push("## When to use Blotato (template-specific)");
  for (const u of body.useCases) {
    lines.push(`- ${u}`);
  }
  lines.push("");
  lines.push("## Canonical end-to-end recipe");
  lines.push(
    "Per Blotato's 'Build Your First AI Automation' tutorial, the agent sequence is:"
  );
  lines.push("");
  lines.push(
    "1. **blotato_list_accounts** — always first. Get the `accountId` for the target platform. For Facebook / LinkedIn Company Pages, also call **blotato_list_subaccounts** to get `pageId`. For YouTube, also call subaccounts to get `playlistIds`."
  );
  lines.push(
    "2. **blotato_create_source** *(optional — when republishing from a source URL)*. Wrap inputs in a `source` object (NOT top-level). sourceType has NO auto-detection — pick from: text, article, youtube, twitter, tiktok, perplexity-query, audio, pdf."
  );
  lines.push(
    "3. **Poll blotato_get_source_status** every 2-5 seconds until `status: 'completed'`. **Wait 10+ seconds before the FIRST poll on long YouTube videos / PDFs** — extraction is slow on long content. Extract `content` and `title` from the response."
  );
  lines.push(
    "4. **blotato_create_visual** *(optional — when generating a video / carousel from a Blotato template)*. **Recommended pattern: set `inputs: {}` and describe what you want in `prompt`** — Blotato AI auto-fills template inputs. Pass the bare UUID as `templateId` (NOT the path form `/base/v2/...`)."
  );
  lines.push(
    "5. **Poll blotato_get_visual_status** every 5 seconds. Status lifecycle: `queueing` → `generating-script` → `script-ready` → `generating-media` → `media-ready` → `exporting` → `done`. Pull `mediaUrl` and/or `imageUrls` from the response."
  );
  lines.push(
    "6. **blotato_create_post** with the mediaUrl(s) from step 5 in `content.mediaUrls`. Match `content.platform` to `target.targetType`. Use root-level `scheduledTime` or `useNextFreeSlot` for scheduling (NOT nested in `post` — that's silently ignored)."
  );
  lines.push(
    "7. **Poll blotato_get_post_status** every 2-5 seconds until `status: 'published'`. Record the returned `publicUrl` to Message Memory."
  );
  lines.push("");
  lines.push("## Failure semantics — load-bearing");
  lines.push(
    "- A `failed` / `creation-from-template-failed` terminal status is **PERMANENT**. Agents do NOT auto-retry the same source / visual / post. Log the `errorMessage`, route to operator, and (where applicable) retry with a different template or different inputs."
  );
  lines.push(
    "- Retry on 5xx HTTP errors only — wait 5-10 seconds with exponential backoff, up to 3 attempts."
  );
  lines.push(
    "- Fail immediately on 4xx — that's a malformed request or auth issue and retrying won't help."
  );
  lines.push(
    "- Respect `Retry-After` on 429 (rate-limit). Rate limits per Blotato: POST /posts and POST /videos and POST /sources at 30/min, GET polls at 60/min, POST /media/uploads at 120/min."
  );
  lines.push("");
  lines.push("## Per-platform required + optional fields (in `target`)");
  lines.push(
    "- **TikTok** (ALL required): `privacyLevel` ('SELF_ONLY' | 'PUBLIC_TO_EVERYONE' | 'MUTUAL_FOLLOW_FRIENDS' | 'FOLLOWER_OF_CREATOR'), `disabledComments`, `disabledDuet`, `disabledStitch`, `isBrandedContent`, `isYourBrand`, `isAiGenerated` (all booleans). Optional: `title` (≤90 chars), `autoAddMusic`, `isDraft`, `imageCoverIndex`, `videoCoverTimestamp`."
  );
  lines.push(
    "- **Facebook**: `pageId` REQUIRED (from blotato_list_subaccounts). For videos, `mediaType: 'reel'` REQUIRED — regular feed videos no longer supported. Reel specs: MP4/MOV/AVI, max 1 GB, min 540×960, 9:16 aspect, 3-90s, 24-60 fps, H.264/H.265 (VP9/AV1 ok), AAC LC 128kbps+ 48kHz stereo. For Stories: `mediaType: 'story'`."
  );
  lines.push(
    "- **YouTube**: `title` REQUIRED, `privacyStatus` ('private' | 'public' | 'unlisted') REQUIRED, `shouldNotifySubscribers` REQUIRED. Optional: `playlistIds` (array, from subaccounts), `thumbnailUrl`, `isMadeForKids`, `containsSyntheticMedia`. YouTube `description` comes from `content.text`."
  );
  lines.push(
    "- **Pinterest**: `boardId` REQUIRED — not available via API. Operator supplies via the MCP config field. Optional: `title`, `altText`, `link`."
  );
  lines.push(
    "- **LinkedIn**: optional `pageId` (omit for personal profile). Document carousels: pass 2-10 image URLs (JPG/PNG) in `content.mediaUrls` and Blotato auto-builds the PDF-style swipeable carousel."
  );
  lines.push(
    "- **Instagram**: optional `mediaType` ('reel' | 'story'), `altText` (≤1000 chars), `collaborators` (≤3 handles, no @), `coverImageUrl` (≤8MB), `shareToFeed`, `audioName`, `trial.graduationStrategy` ('MANUAL' | 'SS_PERFORMANCE') for trial reels (reels only)."
  );
  lines.push(
    "- **X / Bluesky / Threads**: threads via `content.additionalPosts[]` (array of `{text, mediaUrls}` — Blotato handles reply chaining; agent does NOT capture tweet IDs). Threads also supports optional `replyControl` ('everyone' | 'accounts_you_follow' | 'mentioned_only')."
  );
  lines.push("");
  lines.push("## Fan-out pattern — 1 source, N platforms");
  lines.push(
    "When fanning out from one source / visual to multiple platforms:"
  );
  lines.push("");
  lines.push("1. Extract source ONCE (step 2-3 above) or generate visual ONCE.");
  lines.push(
    "2. Submit N parallel **blotato_create_post** calls — one per target platform — each with its own platform-required `target` fields."
  );
  lines.push(
    "3. Poll all N submissions concurrently, staggering polls to respect the 2-5 sec interval (don't all-poll at second 0; offset by 500-1000ms per poll worker)."
  );
  lines.push(
    "4. Record each `publicUrl` to Message Memory linked to a common parent (e.g., the source URL or the visual id) so analytics can trace cross-platform performance back to the same content seed."
  );
  lines.push("");
  lines.push("## Schedule slots — recurring posting cadence");
  lines.push(
    "For consistent cadence (e.g., 'Mon/Wed/Fri 9am LinkedIn + Tue/Thu 4pm TikTok'), use schedule slots:"
  );
  lines.push("");
  lines.push(
    "1. **One-time setup**: blotato_create_schedule_slots with an array of `{hour, minute, day, selectedTargets: [{platform, accountId, subaccountId?}]}`."
  );
  lines.push(
    "2. **Per-post publish**: blotato_create_post with `useNextFreeSlot: true` at the ROOT level (NOT nested in `post`). Blotato finds the next open slot for the target platform."
  );
  lines.push(
    "3. **Reschedule-to-next-slot recipe**: blotato_find_next_available_slot({platform, accountId}) → returns `{slot: {slotId, slotTime}}` → blotato_update_schedule with `patch.scheduledTime = slotTime`. The update endpoint does NOT accept `useNextFreeSlot` directly."
  );
  lines.push("");
  lines.push("## Plan-cap awareness");
  lines.push(
    "- Starter: 20 connected accounts, 400MB upload, 200 queued scheduled posts, 9-month scheduling horizon."
  );
  lines.push(
    "- Creator: 40 accounts, 1GB upload, 1000 queued posts, 12-month horizon."
  );
  lines.push(
    "- Agency: 100 accounts, 1GB upload, 3000 queued posts, 24-month horizon."
  );
  lines.push(
    "- Free Trial includes API access — same workflow, same tools, time-limited."
  );
  lines.push(
    "- Facebook Pages and LinkedIn Company Pages do NOT count toward the accounts cap."
  );
  lines.push(
    "- **Before bulk-scheduling**, call blotato_list_schedules to see remaining queue capacity. Exceeding a plan limit on POST /posts returns HTTP 422; for async POSTs like /media the job transitions to `status: 'failed'`."
  );
  lines.push("");
  lines.push("## Critical rules — re-read before EVERY publish");
  lines.push(
    "1. `content.platform` and `target.targetType` MUST be the same string value (e.g., both `'twitter'`)."
  );
  lines.push(
    "2. `mediaUrls` is REQUIRED on `content` — pass `[]` for text-only posts."
  );
  lines.push(
    "3. `scheduledTime` and `useNextFreeSlot` are ROOT-LEVEL fields, siblings of `post` — NOT inside `post.options` or `post`. If nested, scheduling is silently ignored and the post publishes immediately."
  );
  lines.push(
    "4. `templateId` (in blotato_create_visual) is the bare UUID, NOT the full path form."
  );
  lines.push(
    "5. Do NOT also call blotato_create_post when editing a schedule via blotato_update_schedule — that creates duplicates at publish time."
  );
  lines.push(
    "6. blotato_update_schedule does NOT merge partial drafts — GET the schedule first, edit in place, PATCH the whole object back."
  );
  lines.push(
    "7. Brand voice + compliance rules from {{businessName}}'s template (Rule 0, approved/prohibited language, Compliance Officer pre-publish review) apply to every Blotato post. Blotato is the publishing layer, NOT a bypass of compliance review."
  );
  lines.push("");
  lines.push(`## Worked example — ${body.templateName}`);
  lines.push("");
  lines.push(body.workedExample);
  lines.push("");
  lines.push("---");
  lines.push(
    "Reference docs: https://help.blotato.com/api/start · https://help.blotato.com/api/llm.md · https://help.blotato.com/api/workflows.md · https://help.blotato.com/api/templates/11-build-your-first-ai-automation.md"
  );

  return {
    category: "playbook",
    title: "Blotato Operational Playbook",
    contentTemplate: lines.join("\n")
  };
}

function baseDocs(note: string): StarterDocTemplate[] {
  return [
    {
      filePath: "AGENTS.md",
      category: "core",
      tier: "hot",
      contentTemplate: `# {{businessName}} Agents

Use this workspace to document the operating rules for {{businessName}}'s agent team.

${note}
`
    },
    {
      filePath: "WORKFLOWS.md",
      category: "timeline",
      tier: "warm",
      contentTemplate: `# {{businessName}} Workflows

Track automation rules, approvals, schedules, and launch notes for {{businessName}} here.
`
    }
  ];
}

// ─── Self Learning AI Engine — universal, auto-injected ───────────────
// Four learning capabilities exist platform-wide in Ghost ProtoClaw:
//   1. Persistent Memory (AgentMemory table, scoped by agentId + businessId)
//   2. Past-Task Learning (learn_from_outcome tool, in BUILTIN_ALWAYS_ON)
//   3. Pattern Recognition (agents analyze their own memory before tasks)
//   4. Team Intelligence (delegate_task for leaders, shared knowledge base)
//
// These constants are auto-injected by materializeTemplate() into every
// new business. Templates with richer template-specific equivalents
// (Ghost Operator's LEARNING_LOG, TikTok Shop's winner-extraction
// workflow) take precedence via dedup — the universal versions fill in
// where templates don't have their own. The blank template opts out.

export const SELF_LEARNING_ENGINE_KB: StarterKnowledgeTemplate = {
  category: "processes",
  title: "Self Learning AI Engine — how your team gets smarter every week",
  contentTemplate: `# Self Learning AI Engine

{{businessName}}'s agent team has four learning capabilities that compound over time. These are platform-wide features — every agent in every Ghost ProtoClaw business has them by default.

## 1. Persistent Memory
Every agent maintains its own memory scoped to {{businessName}}. Memories persist across conversations, restarts, and deployments. Memory types:

- **conversation_summary** — compressed history of prior chats
- **learned_preference** — operator-specific preferences the agent picked up
- **contact_note** — facts about customers, leads, prospects
- **task_outcome** — results of prior runs (what worked, what didn't)
- **system_observation** — patterns in the business environment

Agents read their own memory before every significant task. New findings are written via the \`learn_from_outcome\` tool.

## 2. Past-Task Learning
Every agent has the \`learn_from_outcome\` tool in its default toolkit. After any task with a measurable outcome — an experiment ran, a campaign launched, a deal closed, content published — the agent records:

- what was tried
- what happened
- what would be done differently next time

These entries populate the agent's memory and are available to itself AND to any agent it delegates to inside {{businessName}}.

## 3. Pattern Recognition
Pattern recognition is not a separate engine — it's what agents produce by reading their own and their teammates' memories before acting. The **Weekly Learning Review** workflow surfaces patterns explicitly: top-performing outputs, recurring failures, rule exceptions. Over time the team gets measurably better at the work because the memory compounds.

## 4. Team Intelligence
Leader agents (the main / CEO agent on every template) can delegate tasks to specialists via the \`delegate_task\` tool. When they do, the specialist inherits the business's shared context + knowledge base. Agent memories stay scoped by default — no cross-contamination — but knowledge items are shared and any agent can reference another's published work via \`knowledge_lookup\`.

## The learning loop protocol
Every agent follows the same loop after any non-trivial task:

1. Read prior outcomes in memory related to this task type
2. Execute the task, documenting the attempt
3. Call \`learn_from_outcome\` with {task, outcome, what_worked, what_didnt_work, next_time}
4. If the outcome is significant, escalate to the main agent for team-wide awareness

The Weekly Learning Review workflow (auto-included on every template) surfaces the week's accumulated learnings for operator review. This is how {{businessName}} compounds — not by trying harder, but by remembering better.

## Where memories live
- **AgentMemory** table in the platform database
- Scoped to \`(agentId, businessId)\` — one agent's memory is private to that agent
- **Knowledge items** (via \`knowledge_lookup\`) are shared across the team
- **LEARNING_LOG.md** workspace doc is the human-readable record

## Operator controls
- Review memories in /admin/memory
- Promote memories to knowledge items when something becomes a rule
- Adjust memory tier (hot / warm / cold) to control token budget
- Prune stale entries quarterly

Do NOT delete the learning log. The full history is the team's institutional memory and its growing competitive edge.
`
};

export const LEARNING_LOG_WORKSPACE_DOC: StarterDocTemplate = {
  filePath: "LEARNING_LOG.md",
  category: "core",
  tier: "hot",
  contentTemplate: `# {{businessName}} — Learning Log

Every agent logs here after every significant task. This file grows smarter with every entry. Review the last 10 entries before starting any new campaign, build phase, or strategy shift.

## Entry format

\`\`\`
[DATE] AGENT: name
TASK: what was attempted
OUTCOME: what happened
WHAT WORKED: specific element that succeeded
WHAT DIDN'T WORK: specific element that failed or underperformed
NEXT TIME: concrete action to take differently
\`\`\`

## Rules
1. Entries are never deleted — the full history is the team's memory.
2. If a pattern repeats 3+ times, promote the learning to a knowledge item in /admin/knowledge.
3. Reference this log before starting any non-trivial task in the same category.
4. The Weekly Learning Review workflow reads this log to surface patterns for operator review.

---

## Log entries
(Agents add entries below as they run)
`
};

