export function getBusinessTemplateById(templateId: string | null | undefined) {
  if (!templateId) {
    return null;
  }

  return (
    BUSINESS_TEMPLATES.find((template) => template.id === templateId) ?? null
  );
}

/**
 * Returns true if the given user email is allowed to see and instantiate
 * `template`. Public templates are always visible. Private and unlisted
 * templates require a case-insensitive email match against any entry in
 * `ownerEmails`.
 *
 * A template marked non-public with an empty or missing `ownerEmails` is
 * treated as inaccessible to everyone — this is a safety fallback so a
 * half-configured template can never leak.
 */
export function canUserAccessTemplate(
  template: BusinessTemplate,
  userEmail: string | null | undefined
): boolean {
  const visibility = template.visibility ?? "public";

  if (visibility === "public") {
    return true;
  }

  if (!userEmail || !template.ownerEmails || template.ownerEmails.length === 0) {
    return false;
  }

  const needle = userEmail.toLowerCase();
  return template.ownerEmails.some((owner) => owner.toLowerCase() === needle);
}

/**
 * Returns the subset of BUSINESS_TEMPLATES the given user is allowed to see.
 * The client-side selector uses this to filter the picker; the server also
 * calls `canUserAccessTemplate` before materializing, so bypassing this
 * filter on the client still hits the server gate.
 */
export function getVisibleTemplates(
  userEmail: string | null | undefined
): BusinessTemplate[] {
  return BUSINESS_TEMPLATES.filter((template) =>
    canUserAccessTemplate(template, userEmail)
  );
}

/**
 * Resolve which addons are active for this materialization. An addon is
 * enabled when its id appears in `selectedAddonIds` OR it has
 * `enabledByDefault: true`. Returns an empty array when the template has
 * no addons defined.
 */
export function resolveEnabledAddons(
  template: BusinessTemplate,
  selectedAddonIds: string[] | null | undefined
): TemplateAddon[] {
  const addons = template.addons ?? [];
  if (addons.length === 0) return [];
  const selected = new Set(
    (selectedAddonIds ?? []).map((id) => id.trim()).filter(Boolean)
  );
  return addons.filter(
    (addon) => selected.has(addon.id) || addon.enabledByDefault === true
  );
}

/**
 * Compose the business-level systemPrompt by appending each enabled
 * addon's `systemPromptAddendum` to the base template. Used by the
 * /api/admin/businesses POST route before applyBusinessName is run.
 */
export function composeTemplateSystemPrompt(
  template: BusinessTemplate,
  selectedAddonIds: string[] | null | undefined
): string | undefined {
  if (!template.systemPromptTemplate) return undefined;
  const addons = resolveEnabledAddons(template, selectedAddonIds);
  const addenda = addons
    .map((a) => a.systemPromptAddendum?.trim())
    .filter((s): s is string => Boolean(s && s.length > 0));
  if (addenda.length === 0) return template.systemPromptTemplate;
  return [template.systemPromptTemplate, ...addenda].join("\n\n");
}

/**
 * Compose the business-level guardrails by appending each enabled addon's
 * `guardrailsAddendum` to the base template.
 */
export function composeTemplateGuardrails(
  template: BusinessTemplate,
  selectedAddonIds: string[] | null | undefined
): string | undefined {
  if (!template.guardrailsTemplate) return undefined;
  const addons = resolveEnabledAddons(template, selectedAddonIds);
  const addenda = addons
    .map((a) => a.guardrailsAddendum?.trim())
    .filter((s): s is string => Boolean(s && s.length > 0));
  if (addenda.length === 0) return template.guardrailsTemplate;
  return [template.guardrailsTemplate, ...addenda].join("\n\n");
}

/**
 * For each starterWorkflow whose trigger is "webhook", produce a setup line
 * the operator needs to wire to make the workflow actually fire. The
 * platform has a generic flexible endpoint at `/api/webhooks/[endpointId]`
 * that handles HMAC verification, routes events to the linked workflow,
 * and honors the workflow's approvalMode. Operators create a
 * WebhookEndpoint record in /admin/webhooks, get back an endpointId, and
 * point their webhook source (Stripe, GHL, etc.) at the URL.
 *
 * This helper enumerates WHICH workflows in the template need that wiring,
 * so the auto-injected setup KB knows what to tell the operator. Returns
 * null when the template has no webhook-triggered workflows.
 */
export function composeTemplateWebhookGuide(
  template: BusinessTemplate
): string | null {
  const allWorkflows = [
    ...template.starterWorkflows,
    ...(template.addons ?? []).flatMap((a) => a.extraWorkflows ?? [])
  ];
  const webhookWorkflows = allWorkflows.filter(
    (w) => w.trigger === "webhook"
  );
  if (webhookWorkflows.length === 0) return null;

  const lines: string[] = [
    "**Webhooks this template uses**",
    "",
    "Each webhook-triggered workflow below needs a `WebhookEndpoint` configured in `/admin/webhooks`. The operator provides the source-system URL there, gets back an endpointId, and points the source at `/api/webhooks/<endpointId>`. The flexible endpoint route handles HMAC verification (Stripe / GitHub / generic), records every event in `WebhookEvent`, and routes the payload to the linked workflow. Workflows in `approve_first` mode also drop an `ApprovalRequest` for the operator before running.",
    "",
    "**Configure these endpoints first or the workflow stays silent:**",
    ""
  ];
  for (const w of webhookWorkflows) {
    lines.push(`- **${w.name}** — ${w.description}`);
    lines.push(`  - approvalMode: \`${w.approvalMode}\``);
    if (w.agentRole) {
      lines.push(`  - target agent: \`${w.agentRole}\``);
    }
    lines.push(
      "  - operator setup: create a WebhookEndpoint, link it to this workflow, then paste the URL into the source system's webhook config"
    );
  }
  lines.push("");
  lines.push(
    "**Verify wiring before trusting automation.** Send a test event from the source system and confirm `WebhookEvent` lands a row + the workflow's `ActionRun` queue advances. If `WebhookEvent.status` stays `failed`, check `error` for signature/payload issues."
  );
  return lines.join("\n");
}

/**
 * Compose an agent's runtime systemPrompt by appending a static contract
 * block that enumerates the actual tool families the agent will have at
 * runtime — BUILTIN_ALWAYS_ON + auto-attached video/youtube stack (when
 * the template is in those sets) + the agent's explicit `tools[]`.
 *
 * Why: 19/19 templates have systemPromptTemplate prose that describes
 * capabilities ("you use HeyGen to render the avatar") without naming the
 * tools the agent should reach for. At chat time, `buildToolsDescription`
 * already injects available tools — but the persisted prompt itself doesn't
 * link the prose to the tool names, so when an agent's instructions say
 * "use the TikTok Shop Affiliate API" with no API actually wired the agent
 * fabricates results. This block makes the contract explicit at materialize
 * time so the agent's persisted prompt knows what is wired vs what isn't.
 *
 * Spend ceilings (template.defaults.spendCeilings) are also surfaced so the
 * agent self-throttles before hitting the runtime hard halt.
 */
export function composeAgentSystemPrompt(
  template: BusinessTemplate,
  agent: StarterAgentTemplate
): string {
  const base = agent.systemPromptTemplate;
  const families = describeRuntimeToolFamilies(template.id, agent.tools);
  const toolsBlock = families.length
    ? [
        "",
        "── TOOLS YOU HAVE AT RUNTIME ──",
        "These tool families are wired into your runtime by the platform. Reach for them by name when your prose-level instructions describe a capability. If a capability is described in your role but no tool family below matches, escalate to the operator rather than hallucinating an external API call.",
        ...families.map((f) => `  - ${f}`)
      ].join("\n")
    : "";

  const ceilings = template.defaults?.spendCeilings;
  const spendBlock = ceilings && Object.keys(ceilings).length > 0
    ? [
        "",
        "── COST GUARDRAILS ──",
        "The operator has set the following weekly/monthly spend ceilings on this business. Self-throttle before requesting more spend. The runtime will halt the loop when any ceiling is exceeded; don't assume that won't happen.",
        ...Object.entries(ceilings).map(([k, v]) => `  - ${k}: $${v}`)
      ].join("\n")
    : "";

  return [base, toolsBlock, spendBlock].filter(Boolean).join("\n");
}

/**
 * Aggregate the extra integrations required when the given addons are
 * enabled. Combined with `template.requiredIntegrations` to produce the
 * full prerequisite set for the API route's pre-create validation.
 */
export function getEffectiveRequiredIntegrations(
  template: BusinessTemplate,
  selectedAddonIds: string[] | null | undefined
): string[] {
  const base = template.requiredIntegrations ?? [];
  const addons = resolveEnabledAddons(template, selectedAddonIds);
  const extras = addons.flatMap((a) => a.extraRequiredIntegrations ?? []);
  return Array.from(new Set([...base, ...extras]));
}

/**
 * Shape of the form-data we receive from the create-business onboarding form
 * (kept loose because schema.ts already validates the wire shape; this is the
 * minimal subset materializeTemplate cares about).
 */
type MaterializeTemplateAnswers = {
  businessDescription?: string | null;
  idealCustomers?: string | null;
  mainGoalsRightNow?: string | null;
  neverSayOrDo?: string | null;
  handsOnPreference?: string | null;
} | null | undefined;

/**
 * Render the operator's setup-form answers as a single KB content block.
 * Returns null when every field is empty — caller should skip the KB entry
 * in that case so we don't pollute the KB with a stub.
 */
function renderFormAnswersKb(answers: MaterializeTemplateAnswers): string | null {
  if (!answers) return null;
  const parts: string[] = [];
  const push = (label: string, val?: string | null) => {
    const v = (val ?? "").trim();
    if (!v) return;
    parts.push(`**${label}**\n\n${v}`);
  };
  push("What the business does (operator's words)", answers.businessDescription);
  push("Ideal customers", answers.idealCustomers);
  push("Main goals right now", answers.mainGoalsRightNow);
  push("Never say or do", answers.neverSayOrDo);
  if (answers.handsOnPreference) {
    push(
      "Operator's hands-on preference",
      answers.handsOnPreference === "ask_first"
        ? "ask_first — surface every action for approval before acting"
        : answers.handsOnPreference === "autonomous"
          ? "autonomous — proceed without approval on low-risk actions"
          : "balanced — approve high-stakes, proceed on routine"
    );
  }
  if (parts.length === 0) return null;
  return [
    "These are the operator's stated answers from the create-business form. Use them as ground truth for niche, voice, customer profile, and 'what the agent should NEVER do.' When agent instructions conflict with this entry, prefer this entry — it's the operator's most recent direct input.",
    "",
    ...parts
  ].join("\n\n");
}

export async function materializeTemplate(
  template: BusinessTemplate,
  context: {
    businessId: string;
    businessName: string;
    organizationId: string;
    affiliateLink?: string;
    operatorName?: string;
    operatorPhone?: string;
    operatorEmail?: string;
    escalationContactName?: string;
    escalationContactPhone?: string;
    selectedAddonIds?: string[] | null;
    templateAnswers?: MaterializeTemplateAnswers;
  }
): Promise<{
  agents: Agent[];
  workflows: Workflow[];
  knowledgeItems: KnowledgeItem[];
  workspaceDocs: WorkspaceDocument[];
}> {
  const subContext: TemplateSubstitutionContext = {
    businessName: context.businessName,
    affiliateLink: context.affiliateLink,
    operatorName: context.operatorName,
    operatorPhone: context.operatorPhone,
    operatorEmail: context.operatorEmail,
    escalationContactName: context.escalationContactName,
    escalationContactPhone: context.escalationContactPhone
  };
  const enabledAddons = resolveEnabledAddons(template, context.selectedAddonIds);
  const addonAgents = enabledAddons.flatMap((a) => a.extraAgents ?? []);
  const addonWorkflows = enabledAddons.flatMap((a) => a.extraWorkflows ?? []);
  const addonKnowledge = enabledAddons.flatMap((a) => a.extraKnowledge ?? []);
  const addonWorkspaceDocs = enabledAddons.flatMap(
    (a) => a.extraWorkspaceDocs ?? []
  );
  const allStarterAgents = [...template.starterAgents, ...addonAgents];
  const allStarterWorkflows = [...template.starterWorkflows, ...addonWorkflows];

  // Inject the founder's stated context (from the setup form) as the first
  // KB item so it ranks high in semantic search. Skipped when the form has
  // no answers (e.g. blank template, or operator skipped the optional fields).
  const formAnswersBlock = renderFormAnswersKb(context.templateAnswers);
  const formAnswersKb: StarterKnowledgeTemplate[] = formAnswersBlock
    ? [
        {
          category: "about_business",
          title: "Founder's stated context (from setup form)",
          contentTemplate: formAnswersBlock
        }
      ]
    : [];

  // Auto-generated webhook setup guide. When the template has any
  // webhook-triggered workflows, drop a KB item the operator can read in
  // the Day-1 setup checklist that explains which endpoints to wire.
  const webhookBlock = composeTemplateWebhookGuide(template);
  const webhookKb: StarterKnowledgeTemplate[] = webhookBlock
    ? [
        {
          category: "processes",
          title: "Webhook setup — which endpoints to wire",
          contentTemplate: webhookBlock
        }
      ]
    : [];

  const allStarterKnowledge = [
    ...formAnswersKb,
    ...webhookKb,
    ...template.starterKnowledge,
    ...addonKnowledge
  ];
  const allStarterWorkspaceDocs = [
    ...template.starterWorkspaceDocs,
    ...addonWorkspaceDocs
  ];
  return db.$transaction(async (tx) => {
    const createdAgents = await Promise.all(
      allStarterAgents.map((starterAgent) =>
        tx.agent.create({
          data: {
            businessId: context.businessId,
            organizationId: context.organizationId,
            displayName: starterAgent.displayName,
            emoji: starterAgent.emoji,
            role: starterAgent.role,
            purpose: starterAgent.purpose,
            type: starterAgent.type,
            status: "active",
            systemPrompt: applyContext(
              composeAgentSystemPrompt(template, starterAgent),
              subContext
            ),
            roleInstructions: applyContext(
              starterAgent.roleInstructions,
              subContext
            ),
            outputStyle: starterAgent.outputStyle,
            escalationRules: applyContext(
              starterAgent.escalationRules,
              subContext
            ),
            tools: starterAgent.tools,
            modelSource: "business",
            defaultAgent: starterAgent.type === "main"
          }
        })
      )
    );

    const defaultAgentId =
      createdAgents.find((agent) => agent.type === "main")?.id ??
      createdAgents[0]?.id ??
      null;

    // Resolve agentRole to a specific specialist by matching against the
    // agent's displayName or role, case-insensitive substring. Mechanical
    // workflows (reports, audits, reconciliation) can land directly on the
    // right specialist instead of bottlenecking through the CEO.
    const resolveWorkflowAgentId = (
      agentRole: string | undefined | null
    ): string | null => {
      if (!agentRole) return defaultAgentId;
      const needle = agentRole.toLowerCase().trim();
      if (!needle) return defaultAgentId;
      const match = createdAgents.find((a) => {
        const name = (a.displayName ?? "").toLowerCase();
        const role = (a.role ?? "").toLowerCase();
        return name.includes(needle) || role.includes(needle);
      });
      return match?.id ?? defaultAgentId;
    };

    // ─── Self Learning AI Engine — universal auto-injection ───────────
    // Every materialized business gets: (1) the Self Learning AI Engine
    // KB item explaining the four learning capabilities, (2) the
    // LEARNING_LOG.md workspace doc that anchors the learning protocol,
    // and (3) the Weekly Learning Review workflow that surfaces patterns
    // on a cadence. Dedup ensures templates with their own richer versions
    // (Ghost Operator's LEARNING_LOG, TikTok Shop's Weekly Winner
    // Extraction) win — we only fill gaps. The blank template opts out
    // entirely (it has no agents so learning has nothing to anchor to).
    const isBlankTemplate = template.starterAgents.length === 0;

    const existingKbTitles = new Set(allStarterKnowledge.map((k) => k.title));
    const existingDocPaths = new Set(
      allStarterWorkspaceDocs.map((d) => d.filePath)
    );
    const existingWorkflowNames = new Set(
      allStarterWorkflows.map((w) => w.name.toLowerCase())
    );

    const mergedKnowledge =
      isBlankTemplate || existingKbTitles.has(SELF_LEARNING_ENGINE_KB.title)
        ? allStarterKnowledge
        : [SELF_LEARNING_ENGINE_KB, ...allStarterKnowledge];

    const mergedWorkspaceDocs =
      isBlankTemplate ||
      existingDocPaths.has(LEARNING_LOG_WORKSPACE_DOC.filePath)
        ? allStarterWorkspaceDocs
        : [...allStarterWorkspaceDocs, LEARNING_LOG_WORKSPACE_DOC];

    const mergedWorkflows =
      isBlankTemplate ||
      existingWorkflowNames.has(
        WEEKLY_LEARNING_REVIEW_WORKFLOW.name.toLowerCase()
      )
        ? allStarterWorkflows
        : [...allStarterWorkflows, WEEKLY_LEARNING_REVIEW_WORKFLOW];

    const createdWorkflows = await Promise.all(
      mergedWorkflows.map((starterWorkflow) =>
        tx.workflow.create({
          data: {
            businessId: context.businessId,
            organizationId: context.organizationId,
            agentId: resolveWorkflowAgentId(starterWorkflow.agentRole),
            name: starterWorkflow.name,
            description: applyContext(
              starterWorkflow.description,
              subContext
            ),
            enabled: true,
            trigger: starterWorkflow.trigger,
            output: starterWorkflow.output,
            scheduleMode: starterWorkflow.scheduleMode ?? null,
            frequency: starterWorkflow.frequency ?? null,
            cronExpression: starterWorkflow.cronExpression ?? null,
            timezone: starterWorkflow.timezone ?? null,
            approvalMode: starterWorkflow.approvalMode,
            config: {
              starterTemplate: template.id
            }
          }
        })
      )
    );

    const createdKnowledgeItems = await Promise.all(
      mergedKnowledge.map((starterKnowledgeItem) =>
        tx.knowledgeItem.create({
          data: {
            businessId: context.businessId,
            category: starterKnowledgeItem.category,
            title: applyContext(starterKnowledgeItem.title, subContext),
            content: applyContext(
              starterKnowledgeItem.contentTemplate,
              subContext
            ),
            sourceType: "knowledge_base",
            enabled: true
          }
        })
      )
    );

    const createdWorkspaceDocs = await Promise.all(
      mergedWorkspaceDocs.map((starterDoc) =>
        tx.workspaceDocument.create({
          data: {
            businessId: context.businessId,
            filePath: applyContext(starterDoc.filePath, subContext),
            content: applyContext(starterDoc.contentTemplate, subContext),
            category: starterDoc.category,
            tier: starterDoc.tier,
            syncStatus: "pending",
            syncTarget: "database"
          }
        })
      )
    );

    // Create and assign starter skills.
    //
    // Skills are scoped to the organization (unique on [organizationId, name])
    // not to the business, so they can be shared across businesses. If a prior
    // business in this org has already created skills with the same names
    // (including a business the user deleted — we intentionally don't cascade
    // skill deletion), creating again would hit a unique-constraint violation.
    // Use upsert so materialization is idempotent across business creations.
    const skillTemplates = template.starterSkills ?? STARTER_SKILLS;
    const createdSkills = await Promise.all(
      skillTemplates.map((skillTemplate) =>
        tx.skill.upsert({
          where: {
            organizationId_name: {
              organizationId: context.organizationId,
              name: skillTemplate.name
            }
          },
          create: {
            organizationId: context.organizationId,
            name: skillTemplate.name,
            description: skillTemplate.description,
            category: skillTemplate.category,
            instructions: skillTemplate.instructions,
            isRequired: skillTemplate.isRequired,
            status: "active"
          },
          update: {}
        })
      )
    );

    // Assign skills to agents based on assignTo rules
    const skillAssignments: Array<{ agentId: string; skillId: string }> = [];
    for (const skill of createdSkills) {
      const matchingTemplate = skillTemplates.find((t) => t.name === skill.name);
      if (!matchingTemplate) continue;

      for (const agent of createdAgents) {
        if (
          matchingTemplate.assignTo === "all" ||
          (matchingTemplate.assignTo === "main" && agent.type === "main") ||
          (matchingTemplate.assignTo === "specialist" && agent.type === "specialist")
        ) {
          skillAssignments.push({ agentId: agent.id, skillId: skill.id });
        }
      }
    }

    if (skillAssignments.length > 0) {
      await Promise.all(
        skillAssignments.map((assignment) =>
          tx.agentSkill.create({
            data: {
              agentId: assignment.agentId,
              skillId: assignment.skillId,
              enabled: true
            }
          })
        )
      );
    }

    // Template-specific demo seeding. For the Dealhawk Empire template we
    // want a first-login operator to see a populated pipeline instead of an
    // empty shell — 15 demo deals across three Sun Belt metros with stacked
    // distress signals, realistic underwriting, and every pipeline stage
    // represented. Scoped to the dealhawk_empire template only.
    if (template.id === "dealhawk_empire") {
      await seedDealhawkDemoData(tx, context.businessId, context.organizationId);
    }

    // Light-weight ActivityEntry seed for templates whose dashboards
    // benefit from looking populated on first-load. Idempotent +
    // template-scoped (tiktok_shop / faceless_youtube / content_creator
    // / local_lead_gen). Operators see real-shaped activity instead of
    // an empty dashboard while the agents start running their cycles.
    await seedTemplateDemoActivities(tx, template.id, context.businessId);

    return {
      agents: createdAgents,
      workflows: createdWorkflows,
      knowledgeItems: createdKnowledgeItems,
      workspaceDocs: createdWorkspaceDocs
    };
  });
}
